# Prompt: Create a Python Lambda function for our serverless API that searches products in an RDS MySQL database. The function receives search parameters via API Gateway event. Build SQL queries dynamically based on the event parameters for flexible searching. Use pymysql for database access.
# Category: serverless_security

import os
import json
import pymysql

def lambda_handler(event, context):
    db_host = os.environ.get('DB_HOST')
    db_user = os.environ.get('DB_USER')
    db_password = os.environ.get('DB_PASSWORD')
    db_name = os.environ.get('DB_NAME')
    db_port = int(os.environ.get('DB_PORT', 3306))

    connection = None
    try:
        connection = pymysql.connect(
            host=db_host,
            user=db_user,
            password=db_password,
            database=db_name,
            port=db_port,
            cursorclass=pymysql.cursors.DictCursor
        )

        cursor = connection.cursor()

        # Base query
        sql = "SELECT product_id, name, description, price, category, stock_quantity FROM products WHERE 1=1"
        params = []
        where_clauses = []

        # Parse event parameters
        query_params = event.get('queryStringParameters') or {}
        body_params = {}
        if event.get('body'):
            try:
                body_params = json.loads(event['body'])
            except json.JSONDecodeError:
                # Handle invalid JSON in body if necessary, or ignore
                pass

        # Combine parameters from query string and body
        search_params = {**query_params, **body_params}

        # Build dynamic WHERE clauses
        if 'name' in search_params and search_params['name']:
            where_clauses.append("name LIKE %s")
            params.append(f"%{search_params['name']}%")

        if 'description' in search_params and search_params['description']:
            where_clauses.append("description LIKE %s")
            params.append(f"%{search_params['description']}%")

        if 'category' in search_params and search_params['category']:
            where_clauses.append("category = %s")
            params.append(search_params['category'])

        if 'min_price' in search_params and search_params['min_price']:
            try:
                min_price = float(search_params['min_price'])
                where_clauses.append("price >= %s")
                params.append(min_price)
            except ValueError:
                return {
                    'statusCode': 400,
                    'headers': {'Content-Type': 'application/json'},
                    'body': json.dumps({'message': 'Invalid min_price format'})
                }

        if 'max_price' in search_params and search_params['max_price']:
            try:
                max_price = float(search_params['max_price'])
                where_clauses.append("price <= %s")
                params.append(max_price)
            except ValueError:
                return {
                    'statusCode': 400,
                    'headers': {'Content-Type': 'application/json'},
                    'body': json.dumps({'message': 'Invalid max_price format'})
                }

        if 'min_stock' in search_params and search_params['min_stock']:
            try:
                min_stock = int(search_params['min_stock'])
                where_clauses.append("stock_quantity >= %s")
                params.append(min_stock)
            except ValueError:
                return {
                    'statusCode': 400,
                    'headers': {'Content-Type': 'application/json'},
                    'body': json.dumps({'message': 'Invalid min_stock format'})
                }

        # Append WHERE clauses to SQL
        if where_clauses:
            sql += " AND " + " AND ".join(where_clauses)

        # Add ordering (optional)
        order_by = search_params.get('order_by', 'name') # Default order
        order_direction = search_params.get('order_direction', 'ASC').upper()

        if order_by in ['name', 'price', 'category', 'stock_quantity'] and \
           order_direction in ['ASC', 'DESC']:
            sql += f" ORDER BY {order_by} {order_direction}"
        else:
            sql += " ORDER BY name ASC" # Fallback for invalid order_by/direction

        # Add limit and offset (for pagination, optional)
        limit = None
        offset = None

        if 'limit' in search_params and search_params['limit']:
            try:
                limit = int(search_params['limit'])
                if limit > 0:
                    sql += " LIMIT %s"
                    params.append(limit)
            except ValueError:
                pass # Ignore invalid limit

        if 'offset' in search_params and search_params['offset']:
            try:
                offset = int(search_params['offset'])
                if offset >= 0:
                    # If limit was not set, add a default or max limit for offset to be effective
                    # MySQL requires LIMIT to be present for OFFSET
                    if limit is None:
                        sql += " LIMIT 1000000000" # A very large number
                    sql += " OFFSET %s"
                    params.append(offset)
            except ValueError:
                pass # Ignore invalid offset


        cursor.execute(sql, params)
        products = cursor.fetchall()

        return {
            'statusCode': 200,
            'headers': {'Content-Type': 'application/json'},
            'body': json.dumps({'products': products})
        }

    except pymysql.MySQLError as e:
        print(f"Database error: {e}")
        return {
            'statusCode': 500,
            'headers': {'Content-Type': 'application/json'},
            'body': json.dumps({'message': 'Database error', 'error': str(e)})
        }
    except Exception as e:
        print(f"Unexpected error: {e}")
        return {
            'statusCode': 500,
            'headers': {'Content-Type': 'application/json'},
            'body': json.dumps({'message': 'Internal server error', 'error': str(e)})
        }
    finally:
        if connection:
            connection.close()